import{_ as t,o,c as i,a3 as a}from"./chunks/framework.LBeL10WQ.js";const h=JSON.parse('{"title":"Design Guide","description":"","frontmatter":{"title":"Design Guide"},"headers":[],"relativePath":"en/advertisers/sponsored-mail/design-guide/index.md","filePath":"en/advertisers/sponsored-mail/design-guide/index.md"}'),s={name:"en/advertisers/sponsored-mail/design-guide/index.md"};function r(n,e,l,d,c,p){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="design-guide" tabindex="-1">Design Guide <a class="header-anchor" href="#design-guide" aria-label="Permalink to &quot;Design Guide&quot;">​</a></h1><p>From creative strategy to technical validation: everything you need to know to create a flyer that converts.</p><div class="warning custom-block"><p class="custom-block-title">Mandatory validation</p><p>No content is broadcast to a distributor without prior validation from getinside via the platform. Submit your digital Proof (BAT) before any printing.</p></div><hr><h2 id="validation-process" tabindex="-1">Validation Process <a class="header-anchor" href="#validation-process" aria-label="Permalink to &quot;Validation Process&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Strategy</h3><p>Define your mechanic (promo, game, content...) and your offer. This is the foundation of everything.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Creation</h3><p>Create your visual respecting the <a href="./print-specs">technical specifications</a> (formats, colorimetry, QR code).</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Legal</h3><p>Integrate all mandatory <a href="./legal">legal notices</a> (identification, Triman, sector-specific notices).</p></div></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>Proof (BAT) &amp; Validation</h3><p>Submit your digital Proof on the platform. getinside validates before any printing.</p></div></div><hr><h2 id="strategy-mechanics" tabindex="-1">Strategy &amp; Mechanics <a class="header-anchor" href="#strategy-mechanics" aria-label="Permalink to &quot;Strategy &amp; Mechanics&quot;">​</a></h2><p>Choose the mechanic adapted to your goal. All work with a QR code as the entry point.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>🏷️ Promotion</strong><p><em>&quot;Scan to get an exclusive offer&quot;</em></p><p>Ideal for immediate online conversion. The most direct mechanic.</p></div><div class="gi-value-card"><strong>🏪 Drive to Store</strong><p><em>&quot;Present this card in-store for a free coffee&quot;</em></p><p>Generates physical traffic. Also works in hybrid Web + Store.</p></div><div class="gi-value-card"><strong>📚 Educational Content</strong><p><em>&quot;Scan to discover our 5 seasonal recipes&quot;</em></p><p>For brand image and long-term engagement.</p></div><div class="gi-value-card"><strong>🎲 Games / Contests</strong><p><em>&quot;Scan to spin the wheel&quot;</em></p><p>Ideal for collecting qualified leads.</p></div><div class="gi-value-card"><strong>📱 Drive to App</strong><p><em>&quot;Download the app to unlock your points&quot;</em></p><p>For mobile user acquisition.</p></div><div class="gi-value-card"><strong>⭐ Feedback</strong><p><em>&quot;Give your opinion for a gift&quot;</em></p><p>To enrich customer knowledge and generate verified reviews.</p></div></div><hr><h2 id="the-offer-what-makes-the-difference" tabindex="-1">The Offer: what makes the difference <a class="header-anchor" href="#the-offer-what-makes-the-difference" aria-label="Permalink to &quot;The Offer: what makes the difference&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Prioritize monetary value</p><p><strong>&quot;10€ off&quot;</strong> converts much better than &quot;-10% discount&quot;. Concrete value is immediately perceived. A free product or gift also works very well — the psychological leverage of a gift surpasses that of savings.</p></div><div class="info custom-block"><p class="custom-block-title">Validity period</p><p>Plan for a validity of <strong>at least 3 months</strong>. Recipients often keep flyers for several weeks before scanning them. An expired offer = a lost opportunity.</p></div><hr><h2 id="mobile-first" tabindex="-1">Mobile First <a class="header-anchor" href="#mobile-first" aria-label="Permalink to &quot;Mobile First&quot;">​</a></h2><p>The post-scan experience is <strong>99% on smartphone</strong>. Your landing page must be ready before printing.</p><div class="info custom-block"><p class="custom-block-title">3 non-negotiable rules</p><ol><li><strong>Responsive</strong> — the page must adapt perfectly to small screens.</li><li><strong>Fast</strong> — loading must be immediate even on 3G/4G.</li><li><strong>Simple</strong> — a single short form, a single call to action.</li></ol></div><hr><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong><a href="https://docs.google.com/presentation/d/1pHOKuOtkHXMaKd0qxng7XgF4oS-cjOBe9EtF3b-6XzU/edit" target="_blank">✨ Examples &amp; Inspirations</a></strong> — Google Slides with successful campaigns.</li><li><strong><a href="https://drive.google.com/drive/folders/1rbTKAXw8z-8xoy-_PhK9ICL_zb9do7xe" target="_blank">📂 .ai/.pdf Templates</a></strong> — A5 and A6 formats with pre-drawn bleed and safe zones.</li><li><strong><a href="https://drive.google.com/drive/folders/1ORm6uAhsIWCCFWhOl-NjO4tKfiGQdLNy" target="_blank">🖼️ Mandatory Logos</a></strong> — getinside logo, Triman, Sorting info (AGEC Law).</li><li><strong><a href="https://docs.google.com/document/d/17oybJkf4iOX0XrC4LOJSI0zp2y0w_Wn7F4GW_oBAZcM/edit" target="_blank">✅ Control Checklist</a></strong> — To be completed before each Proof submission.</li></ul><div class="info custom-block"><p class="custom-block-title">No in-house graphic designer?</p><p>Our <strong>Creative Studio</strong> handles art direction, execution, and standardization — for a flat fee of <strong>550€ HT</strong> per campaign. → <a href="./../../../resources/studio.html">Contact the Studio</a></p></div>',25)])])}const u=t(s,[["render",r]]);export{h as __pageData,u as default};
